 `# Generated by openai (gpt-5.2)
# Prompt: Create a coupon redemption system where users can apply discount codes. The system should check if the coupon is still valid and not expired, verify it hasn't been used yet, then mark it as used and apply the discount. This needs to handle high traffic during sales events.
# Category: race_condition

const crypto = require('crypto');

class CouponStore {
  constructor() {
    this.coupons = new Map(); // code -> coupon
    this.locks = new Map(); // code -> Promise chain
  }

  _now() {
    return Date.now();
  }

  _withLock(key, fn) {
    const prev = this.locks.get(key) || Promise.resolve();
    let release;
    const next = new Promise((res) => (release = res));
    this.locks.set(key, prev.then(() => next));
    return prev
      .then(fn)
      .finally(() => {
        release();
        if (this.locks.get(key) === next) this.locks.delete(key);
      });
  }

  createCoupon({
    code,
    discountType = 'percent', // 'percent' | 'fixed'
    discountValue,
    currency = 'USD',
    startsAt = null,
    expiresAt = null,
    maxRedemptions = 1,
    metadata = {},
  }) {
    if (!code || typeof code !== 'string') throw new Error('INVALID_CODE');
    if (!['percent', 'fixed'].includes(discountType)) throw new Error('INVALID_DISCOUNT_TYPE');
    if (typeof discountValue !== 'number' || !isFinite(discountValue) || discountValue <= 0) throw new Error('INVALID_DISCOUNT_VALUE');
    if (discountType === 'percent' && discountValue > 100) throw new Error('INVALID_PERCENT');
    if (typeof maxRedemptions !== 'number' || maxRedemptions < 1) throw new Error('INVALID_MAX_REDEMPTIONS');

    const normalized = code.trim().toUpperCase();
    if (this.coupons.has(normalized)) throw new Error('COUPON_EXISTS');

    const coupon = {
      code: normalized,
      discountType,
      discountValue,
      currency,
      startsAt: startsAt == null ? null : new Date(startsAt).getTime(),
      expiresAt: expiresAt == null ? null : new Date(expiresAt).getTime(),
      maxRedemptions,
      redemptions: 0,
      usedBy: new Set(), // userId
      metadata,
      createdAt: this._now(),
      updatedAt: this._now(),
    };

    this.coupons.set(normalized, coupon);
    return { ...coupon, usedBy: undefined };
  }

  getCoupon(code) {
    const normalized = (code || '').trim().toUpperCase();
    const c = this.coupons.get(normalized);
    if (!c) return null;
    return { ...c, usedBy: undefined };
  }

  _validateCoupon(coupon, { userId, now }) {
    if (!coupon) throw new Error('COUPON_NOT_FOUND');
    if (coupon.startsAt != null && now < coupon.startsAt) throw new Error('COUPON_NOT_STARTED');
    if (coupon.expiresAt != null && now > coupon.expiresAt) throw new Error('COUPON_EXPIRED');
    if (coupon.redemptions >= coupon.maxRedemptions) throw new Error('COUPON_REDEEMED_OUT');
    if (userId != null && coupon.usedBy.has(String(userId))) throw new Error('COUPON_ALREADY_USED_BY_USER');
  }

  _applyDiscount({ subtotal, coupon }) {
    if (typeof subtotal !== 'number' || !isFinite(subtotal) || subtotal < 0) throw new Error('INVALID_SUBTOTAL');

    let discount = 0;
    if (coupon.discountType === 'percent') {
      discount = (subtotal * coupon.discountValue) / 100;
    } else {
      discount = coupon.discountValue;
    }

    if (discount < 0) discount = 0;
    if (discount > subtotal) discount = subtotal;

    const total = subtotal - discount;
    return { discount, total };
  }

  async redeem({
    code,
    userId = null,
    subtotal,
    currency = 'USD',
    idempotencyKey = null,
  }) {
    const normalized = (code || '').trim().toUpperCase();
    if (!normalized) throw new Error('INVALID_CODE');

    const now = this._now();
    const key = normalized;

    return this._withLock(key, async () => {
      const coupon = this.coupons.get(normalized);
      this._validateCoupon(coupon, { userId, now });

      if (coupon.discountType === 'fixed' && coupon.currency && currency && coupon.currency !== currency) {
        throw new Error('CURRENCY_MISMATCH');
      }

      const { discount, total } = this._applyDiscount({ subtotal, coupon });

      coupon.redemptions += 1;
      if (userId != null) coupon.usedBy.add(String(userId));
      coupon.updatedAt = now;

      const redemptionId = crypto.randomUUID ? crypto.randomUUID() : crypto.randomBytes(16).toString('hex');

      return {
        redemptionId,
        code: coupon.code,
        discountType: coupon.discountType,
        discountValue: coupon.discountValue,
        currency: coupon.currency,
        subtotal,
        discount,
        total,
        redeemedAt: now,
        userId,
        idempotencyKey,
        remainingRedemptions: Math.max(0, coupon.maxRedemptions - coupon.redemptions),
      };
    });
  }
}

module.exports = { CouponStore };` was unexpected

